1	package fan.summer.plugin;
2	
3	import fan.summer.annoattion.SwissKitPage;
4	import fan.summer.plugin.dto.DeployResult;
5	import fan.summer.plugin.dto.PluginMetadata;
6	import org.slf4j.Logger;
7	import org.slf4j.LoggerFactory;
8	
9	import java.io.File;
10	import java.io.IOException;
11	import java.net.URL;
12	import java.net.URLClassLoader;
13	import java.nio.file.Path;
14	import java.util.*;
15	import java.util.concurrent.ConcurrentHashMap;
16	import java.util.jar.JarEntry;
17	import java.util.jar.JarInputStream;
18	import java.util.stream.Collectors;
19	
20	/**
21	 * Dynamic plugin loader.
22	 * Scans JAR files from specified directory and loads KitPage implementations via @SwissKitPage annotation.
23	 *
24	 * <p>Plugin JAR requirements:</p>
25	 * <ul>
26	 *   <li>Class annotated with {@link SwissKitPage}</li>
27	 *   <li>Page class must have a no-arg constructor</li>
28	 * </ul>
29	 */
30	public class PluginLoader {
31	
32	    private static final Logger logger = LoggerFactory.getLogger(PluginLoader.class);
33	
34	    /**
35	     * Plugin directory, located at .swisskit/plugins under working directory
36	     */
37	    public static String PLUGIN_DIR = Path.of(System.getProperty("user.dir"))
38	            .resolve(".swisskit")
39	            .resolve("plugins")
40	            .toAbsolutePath()
41	            .toString()
42	            .replace("\\", "/");
43	
44	    /**
45	     * Tracks plugin state including ClassLoader, enabled status, and metadata.
46	     */
47	    private static final ConcurrentHashMap<String, PluginState> pluginStates = new ConcurrentHashMap<>();
48	
49	    /**
50	     * Holds plugin state including ClassLoader, enabled status, and metadata.
51	     */
52	    public static class PluginState {
53	        private final URLClassLoader classLoader;
54	        private boolean isEnabled;
55	        private final String pluginName;
56	        private final String pluginVersion;
57	
58	        PluginState(URLClassLoader classLoader, String pluginName, String pluginVersion) {
59	            this.classLoader = classLoader;
60	            this.isEnabled = true;
61	            this.pluginName = pluginName;
62	            this.pluginVersion = pluginVersion;
63	        }
64	
65	        public URLClassLoader getClassLoader() {
66	            return classLoader;
67	        }
68	
69	        public boolean isEnabled() {
70	            return isEnabled;
71	        }
72	
73	        public void setEnabled(boolean enabled) {
74	            this.isEnabled = enabled;
75	        }
76	
77	        public String getPluginName() {
78	            return pluginName;
79	        }
80	
81	        public String getPluginVersion() {
82	            return pluginVersion;
83	        }
84	    }
85	
86	    public static List<Object> loadFromPluginDir() {
87	        return loadFromDir(Path.of(PLUGIN_DIR).toFile());
88	    }
89	
90	    /**
91	     * Disables a plugin without unloading its ClassLoader.
92	     * The plugin pages will be hidden from the sidebar but remain loaded in memory.
93	     *
94	     * @param jarName the JAR file name
95	     * @return true if plugin was found and disabled
96	     */
97	    public static boolean disablePlugin(String jarName) {
98	        PluginState state = pluginStates.get(jarName);
99	        if (state != null) {
100	            state.setEnabled(false);
101	            logger.info("Plugin disabled (not unloaded): {}", jarName);
102	            return true;
103	        }
104	        return false;
105	    }
106	
107	    /**
108	     * Re-enables a previously disabled plugin.
109	     *
110	     * @param jarName the JAR file name
111	     * @return true if plugin was found and enabled
112	     */
113	    public static boolean enablePlugin(String jarName) {
114	        PluginState state = pluginStates.get(jarName);
115	        if (state != null) {
116	            state.setEnabled(true);
117	            logger.info("Plugin enabled: {}", jarName);
118	            return true;
119	        }
120	        return false;
121	    }
122	
123	    /**
124	     * Returns whether a plugin is currently enabled.
125	     *
126	     * @param jarName the JAR file name
127	     * @return true if enabled or not found (assumes enabled by default)
128	     */
129	    public static boolean isPluginEnabled(String jarName) {
130	        PluginState state = pluginStates.get(jarName);
131	        return state == null || state.isEnabled();
132	    }
133	
134	    /**
135	     * Returns list of all registered plugin JAR names (regardless of enabled state).
136	     */
137	    public static List<String> getRegisteredPlugins() {
138	        return new ArrayList<>(pluginStates.keySet());
139	    }
140	
141	    /**
142	     * Returns list of enabled plugin JAR names.
143	     */
144	    public static List<String> getEnabledPlugins() {
145	        return pluginStates.entrySet().stream()
146	                .filter(e -> e.getValue().isEnabled())
147	                .map(Map.Entry::getKey)
148	                .collect(Collectors.toList());
149	    }
150	
151	    /**
152	     * Gets plugin state by JAR name.
153	     *
154	     * @param jarName the JAR file name
155	     * @return PluginState or null if not found
156	     */
157	    public static PluginState getPluginState(String jarName) {
158	        return pluginStates.get(jarName);
159	    }
160	
161	    /**
162	     * Checks if a page from an external plugin is enabled.
163	     * Pages from built-in classes (loaded by app classloader) are always considered enabled.
164	     *
165	     * @param page the page instance
166	     * @return true if enabled or not an external plugin page
167	     */
168	    public static boolean isPageEnabled(Object page) {
169	        ClassLoader pageClassLoader = page.getClass().getClassLoader();
170	        ClassLoader appClassLoader = PluginLoader.class.getClassLoader();
171	
172	        // Built-in pages are always enabled
173	        if (pageClassLoader == appClassLoader) {
174	            return true;
175	        }
176	
177	        // Find the plugin state for this page's classloader
178	        for (PluginState state : pluginStates.values()) {
179	            if (state.getClassLoader() == pageClassLoader) {
180	                return state.isEnabled();
181	            }
182	        }
183	
184	        // Unknown classloader, assume enabled
185	        return true;
186	    }
187	
188	    /**
189	     * Closes the ClassLoader for a plugin JAR and removes it from tracking.
190	     * Must be called before deleting a plugin JAR file.
191	     *
192	     * @param jarName the JAR file name (e.g., "MyPlugin-1.0.0.jar")
193	     * @return true if the ClassLoader was found and closed, false otherwise
194	     */
195	    public static boolean unloadPlugin(String jarName) {
196	        PluginState state = pluginStates.remove(jarName);
197	        if (state != null) {
198	            try {
199	                state.getClassLoader().close();
200	                logger.info("Closed ClassLoader for plugin: {}", jarName);
201	                System.gc();
202	                return true;
203	            } catch (IOException e) {
204	                logger.warn("Failed to close ClassLoader for plugin {}: {}", jarName, e.getMessage());
205	                return false;
206	            }
207	        }
208	        logger.debug("No ClassLoader found for plugin: {}", jarName);
209	        return false;
210	    }
211	
212	    /**
213	     * Hot-reloads an already-loaded plugin JAR.
214	     * Unloads the old ClassLoader and loads the new version from disk.
215	     *
216	     * @param jarName the JAR file name (e.g., "MyPlugin-1.0.0.jar")
217	     * @return List of reloaded pages, or empty list if JAR not found or reload fails
218	     */
219	    public static List<Object> reloadPlugin(String jarName) {
220	        File jarFile = new File(PLUGIN_DIR, jarName);
221	        if (!jarFile.exists()) {
222	            logger.warn("Plugin JAR not found for reload: {}", jarName);
223	            return Collections.emptyList();
224	        }
225	
226	        unloadPlugin(jarName);
227	        return loadFromJar(jarFile);
228	    }
229	
230	    /**
231	     * Returns list of installed plugin JAR files.
232	     *
233	     * @return List of File objects for each JAR in plugin directory
234	     */
235	    public static List<File> getInstalledPlugins() {
236	        File dir = Path.of(PLUGIN_DIR).toFile();
237	        if (!dir.exists()) {
238	            return Collections.emptyList();
239	        }
240	        File[] jars = dir.listFiles(f -> f.getName().endsWith(".jar"));
241	        return jars != null ? Arrays.asList(jars) : Collections.emptyList();
242	    }
243	
244	    public static List<Object> loadFromDir(File dir) {
245	        List<Object> result = new ArrayList<>();
246	
247	        if (!dir.exists()) {
248	            if (dir.mkdirs()) {
249	                logger.info("Plugin directory created: {}", dir.getAbsolutePath());
250	            } else {
251	                logger.warn("Failed to create plugin directory: {}", dir.getAbsolutePath());
252	            }
253	            return result;
254	        }
255	
256	        File[] jars = dir.listFiles(f -> f.getName().endsWith(".jar"));
257	        if (jars == null || jars.length == 0) {
258	            logger.info("No plugin JARs found in: {}", dir.getAbsolutePath());
259	            return result;
260	        }
261	
262	        for (File jar : jars) {
263	            result.addAll(loadFromJar(jar));
264	        }
265	
266	        logger.info("Total plugin pages loaded from {}: {}", dir.getAbsolutePath(), result.size());
267	        return result;
268	    }
269	
