31	public class SwissKitPageScaner {
32	    private static final Logger logger = LoggerFactory.getLogger(SwissKitPageScaner.class);
33	
34	    /**
35	     * Cached saved menu orders: className -> menuOrder
36	     */
37	    private static final Map<String, Integer> savedMenuOrders = new ConcurrentHashMap<>();
38	
39	    /**
40	     * Built-in page classes
41	     */
42	    private static final List<Class<?>> BUILTIN_PAGE_CLASSES = Arrays.asList(
43	            WelcomePage.class,
44	            ExcelKitPage.class,
45	            EmailKitPage.class,
46	            SettingKitPage.class
47	    );
48	
49	    /**
50	     * Holds scanned pages separated by category.
51	     */
52	    public static class ScannedPages {
53	        private final List<Object> builtinPages;
54	        private final List<Object> pluginPages;
55	
56	        public ScannedPages(List<Object> builtinPages, List<Object> pluginPages) {
57	            this.builtinPages = new ArrayList<>(builtinPages);
58	            this.pluginPages = new ArrayList<>(pluginPages);
59	        }
60	
61	        public List<Object> builtinPages() {
62	            return new ArrayList<>(builtinPages);
63	        }
64	
65	        public List<Object> pluginPages() {
66	            return new ArrayList<>(pluginPages);
67	        }
68	
69	        /**
70	         * Returns total number of pages across both categories.
71	         */
72	        public int totalCount() {
73	            return builtinPages.size() + pluginPages.size();
74	        }
75	
76	        /**
77	         * Returns all pages in order (builtin first, then plugins).
78	         */
79	        public List<Object> toFlatList() {
80	            List<Object> all = new ArrayList<>(builtinPages);
81	            all.addAll(pluginPages);
82	            return all;
83	        }
84	    }
85	
86	    public static ScannedPages scan() {
87	        List<Object> builtinPages = scanBuiltinPages();
88	        List<Object> pluginPages = PluginLoader.loadFromPluginDir();
89	
90	        // Load saved menu orders from DB
91	        loadSavedMenuOrders();
92	
93	        // Sort each category independently: saved user order → annotation order → class name
94	        sortPages(builtinPages);
95	        sortPages(pluginPages);
96	
97	        logger.info("Scanned KitPages - builtin: {}, plugin: {}", builtinPages.size(), pluginPages.size());
98	        return new ScannedPages(builtinPages, pluginPages);
99	    }
100	
101	    private static void sortPages(List<Object> pages) {
102	        pages.sort(Comparator
103	                .comparingInt((Object p) -> {
104	                    Integer saved = savedMenuOrders.get(p.getClass().getName());
105	                    return saved != null ? saved : Integer.MAX_VALUE;
106	                })
107	                .thenComparingInt(p -> getAnnotationOrder(p))
108	                .thenComparing(p -> p.getClass().getName())
109	        );
110	    }
111	
112	    private static int getAnnotationOrder(Object page) {
113	        SwissKitPage annotation = page.getClass().getAnnotation(SwissKitPage.class);
114	        return annotation != null ? annotation.order() : Integer.MAX_VALUE;
115	    }
116	
117	    private static void loadSavedMenuOrders() {
118	        savedMenuOrders.clear();
119	        try (SqlSession session = DatabaseInit.getSqlSession()) {
120	            MenuOrderMapper mapper = session.getMapper(MenuOrderMapper.class);
121	            List<MenuOrderEntity> orders = mapper.selectAll();
122	            for (MenuOrderEntity entity : orders) {
123	                savedMenuOrders.put(entity.getPageClass(), entity.getMenuOrder());
124	            }
