/* SwissKitJ JavaFX Theme - IDEA 2026.1 inspired */

.root {
    -sw-primary: #4895EF;
    -sw-text: #212529;
    -sw-secondary-text: #6C757D;
    -sw-light-gray: #F8F9FA;
    -sw-divider: #E9ECEF;
    -sw-hover: #E8E8E8;
    -sw-selected-bg: #4895EF;
    -sw-selected-text: #FFFFFF;
    -sw-success: #3DC269;
    -sw-warning: #FFA726;
    -sw-error: #EF5350;

    -fx-font-family: "SansSerif", "Segoe UI", "Arial", sans-serif;
    -fx-font-size: 14;
    -fx-background-color: white;
}

/* Menu Item Styles */
.menu-item {
    -fx-background-color: transparent;
    -fx-cursor: hand;
    -fx-alignment: CENTER;
    -fx-padding: 12 10 12 10;
}

.menu-item:hover {
    -fx-background-color: -sw-hover;
}

.menu-item:selected {
    -fx-background-color: -sw-selected-bg;
    -fx-text-fill: -sw-selected-text;
}

/* Sidebar Container */
.sidebar {
    -fx-background-color: -sw-light-gray;
    -fx-pref-width: 160;
}

/* Primary Button */
.btn-primary {
    -fx-background-color: -sw-primary;
    -fx-text-fill: white;
    -fx-padding: 8 20 8 20;
    -fx-cursor: hand;
    -fx-background-radius: 4;
}

.btn-primary:hover {
    -fx-background-color: #3a84d9;
}

.btn-primary:pressed {
    -fx-background-color: #2e6bb8;
}

/* Secondary Button */
.btn-secondary {
    -fx-background-color: transparent;
    -fx-border-color: -sw-divider;
    -fx-border-width: 1;
    -fx-text-fill: -sw-text;
    -fx-padding: 8 20 8 20;
    -fx-cursor: hand;
    -fx-background-radius: 4;
}

.btn-secondary:hover {
    -fx-background-color: -sw-hover;
}

/* Card/Panel */
.card {
    -fx-background-color: white;
    -fx-border-color: -sw-divider;
    -fx-border-width: 1;
    -fx-padding: 16;
    -fx-background-radius: 4;
    -fx-border-radius: 4;
}

/* Input Fields */
.text-field {
    -fx-background-color: white;
    -fx-border-color: -sw-divider;
    -fx-border-width: 1;
    -fx-padding: 8 12 8 12;
    -fx-background-radius: 4;
    -fx-border-radius: 4;
}

.text-field:focused {
    -fx-border-color: -sw-primary;
    -fx-border-width: 2;
}

/* Label Styles */
.label-title {
    -fx-font-size: 18;
    -fx-font-weight: bold;
    -fx-text-fill: -sw-text;
}

.label-header {
    -fx-font-size: 16;
    -fx-font-weight: bold;
    -fx-text-fill: -sw-text;
}

.label-body {
    -fx-font-size: 14;
    -fx-text-fill: -sw-text;
}

.label-secondary {
    -fx-font-size: 14;
    -fx-text-fill: -sw-secondary-text;
}

.label-small {
    -fx-font-size: 12;
    -fx-text-fill: -sw-secondary-text;
}

/* Hyperlink */
.hyperlink {
    -fx-text-fill: -sw-primary;
    -fx-cursor: hand;
}

.hyperlink:hover {
    -fx-underline: true;
}

/* Progress Bar */
.progress-bar {
    -sw-progress-color: -sw-primary;
}

/* ScrollBar */
.scroll-bar > .thumb {
    -fx-background-color: -sw-divider;
}

.scroll-bar > .thumb:hover {
    -fx-background-color: -sw-secondary-text;
}

/* Tooltip */
.tooltip {
    -fx-background-color: -sw-text;
    -fx-text-fill: white;
    -fx-padding: 6 10 6 10;
    -fx-background-radius: 4;
