/* SwissKitJ - Glass UI Theme
   Inspired by macOS titlebar + glass morphism + dark accents
   Based on: toolbox-main-window.html design
*/

/* ── Root Variables ─────────────────────────────────────── */
.root {
    -sw-bg-base: #0d0e11;
    -sw-bg-layer: #13151a;
    -sw-glass-bg: rgba(255, 255, 255, 0.055);
    -sw-glass-bg-hover: rgba(255, 255, 255, 0.09);
    -sw-glass-border: rgba(255, 255, 255, 0.10);
    -sw-glass-border-hi: rgba(255, 255, 255, 0.22);
    -sw-accent: #5b8cf7;
    -sw-accent-soft: rgba(91, 140, 247, 0.18);
    -sw-accent-glow: rgba(91, 140, 247, 0.35);
    -sw-text-primary: rgba(255, 255, 255, 0.92);
    -sw-text-secondary: rgba(255, 255, 255, 0.48);
    -sw-text-tertiary: rgba(255, 255, 255, 0.28);
    -sw-danger: #f25c5c;
    -sw-success: #4cd97b;
    -sw-warning: #f5a623;

    -sw-sidebar-w: 220px;
    -sw-titlebar-h: 44px;
    -sw-radius-sm: 8px;
    -sw-radius-md: 12px;
    -sw-radius-lg: 18px;
    -sw-radius-xl: 24px;

    -fx-font-family: "DM Sans", "Segoe UI", sans-serif;
    -fx-font-size: 14;
    -fx-background-color: -sw-bg-base;
}

/* ── App Window Frame ───────────────────────────────────── */
.app-window {
    -fx-background-color: rgba(13, 14, 17, 0.72);
    -fx-border-color: -sw-glass-border;
    -fx-border-width: 1;
    -fx-border-radius: 24;
    -fx-background-radius: 24;
    -fx-padding: 0;
}

/* ── Titlebar (Custom Borderless) ───────────────────────── */
.titlebar {
    -fx-background-color: rgba(255, 255, 255, 0.025);
    -fx-border-color: -sw-glass-border;
    -fx-border-width: 0 0 1 0;
    -fx-padding: 0 16;
    -fx-alignment: CENTER_LEFT;
    -fx-pref-height: 44;
}

.titlebar-title {
    -fx-text-fill: -sw-text-secondary;
    -fx-font-size: 13;
    -fx-font-weight: 500;
    -fx-alignment: CENTER;
    -fx-translate-x: 0;
}

/* Traffic Lights */
.traffic-lights {
    -fx-spacing: 8;
    -fx-alignment: CENTER_LEFT;
}

.tl-close { -fx-fill: #ff5f57; }
.tl-min   { -fx-fill: #febc2e; }
.tl-max   { -fx-fill: #28c840; }
.tl-icon {
    -fx-font-size: 7;
    -fx-text-fill: rgba(0, 0, 0, 0.5);
    -fx-opacity: 0;
}

/* Titlebar Buttons */
.titlebar-btn {
    -fx-background-color: -sw-glass-bg;
    -fx-border-color: -sw-glass-border;
    -fx-border-width: 1;
    -fx-border-radius: 8;
    -fx-text-fill: -sw-text-secondary;
    -fx-pref-width: 28;
    -fx-pref-height: 28;
    -fx-font-size: 14;
    -fx-cursor: hand;
}

.titlebar-btn:hover {
    -fx-background-color: -sw-glass-bg-hover;
    -fx-border-color: -sw-glass-border-hi;
    -fx-text-fill: -sw-text-primary;
}

/* ── App Body ────────────────────────────────────────────── */
.app-body {
    -fx-background-color: transparent;
}

/* ── Sidebar ──────────────────────────────────────────────── */
.sidebar {
    -fx-background-color: rgba(255, 255, 255, 0.022);
    -fx-border-color: -sw-glass-border;
    -fx-border-width: 0 1 0 0;
    -fx-padding: 12 8;
    -fx-spacing: 2;
    -fx-pref-width: 220;
}

.sidebar-section-label {
    -fx-font-size: 10;
    -fx-font-weight: 500;
    -fx-text-fill: -sw-text-tertiary;
    -fx-letter-spacing: 0.08em;
    -fx-translate-y: 0;
    -fx-padding: 10 10 4 10;
}

.nav-list {
    -fx-spacing: 2;
}

/* Nav Item */
.nav-item {
    -fx-background-color: transparent;
    -fx-border-color: transparent;
    -fx-border-width: 1;
    -fx-border-radius: 8;
    -fx-text-fill: -sw-text-secondary;
    -fx-font-size: 13.5;
    -fx-font-weight: 400;
    -fx-cursor: hand;
