1	package fan.summer.plugin;
2	
3	import fan.summer.database.entity.plugin.PluginManagerEntity;
4	import fan.summer.plugin.dto.DeployResult;
5	import fan.summer.plugin.dto.PluginInfo;
6	import fan.summer.plugin.dto.PluginMetadata;
7	import fan.summer.plugin.dto.PluginUpdateInfo;
8	import fan.summer.scaner.SwissKitPageScaner;
9	import org.slf4j.Logger;
10	import org.slf4j.LoggerFactory;
11	
12	import java.io.File;
13	import java.util.ArrayList;
14	import java.util.List;
15	import java.util.stream.Collectors;
16	
17	/**
18	 * Main facade service for plugin lifecycle management.
19	 * Coordinates between PluginLoader (JAR loading), PluginManager (DB persistence), and UI refresh.
20	 */
21	public class PluginService {
22	
23	    private static final Logger logger = LoggerFactory.getLogger(PluginService.class);
24	
25	    /**
26	     * Deploys a plugin JAR file and registers it in the database.
27	     *
28	     * @param jarFile the JAR file to deploy
29	     * @return PluginInfo with deployment details, or null if deployment failed
30	     */
31	    public static PluginInfo deployPlugin(File jarFile) {
32	        if (jarFile == null || !jarFile.exists()) {
33	            logger.warn("Invalid plugin file for deploy: {}", jarFile);
34	            return null;
35	        }
36	
37	        String jarName = jarFile.getName();
38	
39	        // Deploy and extract metadata via PluginLoader
40	        DeployResult result = PluginLoader.deployPluginWithMetadata(jarFile);
41	        PluginMetadata metadata = result.getMetadata();
42	
43	        if (metadata.getPluginName() == null || metadata.getPluginName().isEmpty()) {
44	            metadata.setPluginName(jarName.replace(".jar", ""));
45	        }
46	        if (metadata.getPluginVersion() == null || metadata.getPluginVersion().isEmpty()) {
47	            metadata.setPluginVersion("1.0.0");
48	        }
49	
50	        // Register in database
51	        PluginManager.registerPlugin(
52	                jarName,
53	                metadata.getPluginName(),
54	                metadata.getPluginVersion(),
55	                metadata.getUpdateUrl()
56	        );
57	
58	        // Refresh UI
59	        SwissKitPageScaner.refreshPluginPages();
60	
61	        // Build and return PluginInfo
62	        PluginInfo info = new PluginInfo(jarName, metadata.getPluginName(), metadata.getPluginVersion());
63	        info.setLoaded(true);
64	        info.setInstalled(true);
65	        info.setEnabled(true);
66	        info.setUpdateUrl(metadata.getUpdateUrl());
67	
68	        logger.info("Plugin deployed successfully: {}", jarName);
69	        return info;
70	    }
71	
72	    /**
73	     * Deploys a plugin from a path string.
74	     *
75	     * @param jarPath the path to the JAR file
76	     * @return PluginInfo with deployment details, or null if deployment failed
77	     */
78	    public static PluginInfo deployPlugin(String jarPath) {
79	        return deployPlugin(new File(jarPath));
80	    }
81	
82	    /**
83	     * Uninstalls a plugin completely.
84	     * Unloads the JAR, unregisters from database, and deletes the JAR file.
85	     *
86	     * @param jarName the JAR file name
87	     * @return true if uninstallation was successful
88	     */
89	    public static boolean uninstallPlugin(String jarName) {
90	        // Unload from memory
91	        boolean unloaded = PluginLoader.unloadPlugin(jarName);
92	        if (!unloaded) {
93	            logger.warn("Plugin was not loaded in memory: {}", jarName);
94	        }
95	
96	        // Unregister from database
97	        PluginManager.unregisterPlugin(jarName);
98	
99	        // Delete JAR file
100	        File jarFile = new File(PluginLoader.PLUGIN_DIR, jarName);
101	        if (jarFile.exists()) {
102	            if (jarFile.delete()) {
103	                logger.info("Plugin JAR deleted: {}", jarName);
104	            } else {
105	                logger.warn("Failed to delete plugin JAR: {}", jarName);
106	            }
107	        }
108	
109	        // Refresh UI
110	        SwissKitPageScaner.refreshPluginPages();
111	
112	        logger.info("Plugin uninstalled: {}", jarName);
113	        return true;
114	    }
115	
116	    /**
117	     * Hot-reloads an already-loaded plugin.
118	     *
119	     * @param jarName the JAR file name
120	     * @return PluginInfo with reloaded plugin details, or null if reload failed
121	     */
122	    public static PluginInfo reloadPlugin(String jarName) {
123	        File jarFile = new File(PluginLoader.PLUGIN_DIR, jarName);
124	        if (!jarFile.exists()) {
125	            logger.warn("Plugin JAR not found for reload: {}", jarName);
126	            return null;
127	        }
128	
129	        // Get existing plugin info before reload
130	        PluginInfo existingInfo = getPluginInfo(jarName);
131	
132	        // Reload via PluginLoader
133	        List<Object> pages = PluginLoader.reloadPlugin(jarName);
134	        if (pages.isEmpty()) {
135	            logger.warn("Plugin reload returned no pages: {}", jarName);
136	        }
137	
138	        // Extract metadata
139	        DeployResult result = PluginLoader.deployPluginWithMetadata(jarFile);
140	        PluginMetadata metadata = result.getMetadata();
141	
142	        // Refresh UI
143	        SwissKitPageScaner.refreshPluginPages();
144	
145	        PluginInfo info = new PluginInfo(jarName, metadata.getPluginName(), metadata.getPluginVersion());
146	        info.setLoaded(true);
147	        info.setInstalled(true);
148	        info.setEnabled(existingInfo != null ? existingInfo.isEnabled() : true);
149	        info.setUpdateUrl(metadata.getUpdateUrl());
150	
151	        logger.info("Plugin reloaded: {}", jarName);
152	        return info;
153	    }
154	
155	    /**
156	     * Disables a plugin both in memory and in database.
157	     *
158	     * @param jarName the JAR file name
159	     * @return true if successful
160	     */
161	    public static boolean disablePlugin(String jarName) {
162	        // Disable in memory
163	        boolean memoryDisabled = PluginLoader.disablePlugin(jarName);
164	        // Disable in database
165	        boolean dbDisabled = PluginManager.disablePlugin(jarName);
166	
167	        if (memoryDisabled || dbDisabled) {
168	            SwissKitPageScaner.refreshPluginPages();
169	            logger.info("Plugin disabled: {}", jarName);
170	            return true;
171	        }
172	        return false;
173	    }
174	
