        // Fade out then close
        FadeTransition fadeOut = new FadeTransition(Duration.millis(200), container);
        fadeOut.setFromValue(1);
        fadeOut.setToValue(0);
        fadeOut.setOnFinished(e -> stage.hide());
        fadeOut.play();
    }

    public void setStatus(String status) {
        statusLabel.setText(status);
    }

    public Parent getRoot() {
        return container;
    }

    private static class Rectangle2D {
        private final double minX, minY, width, height;

        public Rectangle2D(double minX, double minY, double width, double height) {
            this.minX = minX;
            this.minY = minY;
            this.width = width;
            this.height = height;
        }

        public double getWidth() { return width; }
        public double getHeight() { return height; }

        public static Rectangle2D of(double minX, double minY, double width, double height) {
            return new Rectangle2D(minX, minY, width, height);
        }
    }
}

