package fan.summer.controller;

import fan.summer.i18n.I18nManager;
import fan.summer.i18n.Language;
import fan.summer.i18n.LocaleChangeListener;
import fan.summer.scaner.SwissKitPageScaner;
import fan.summer.ui.theme.ThemeManager;
import javafx.fxml.FXML;
import javafx.geometry.Side;
import javafx.scene.Node;
import javafx.scene.control.Label;
import javafx.scene.control.Tooltip;
import javafx.scene.layout.FlowPane;
import javafx.scene.layout.HBox;
import javafx.scene.layout.StackPane;
import javafx.scene.layout.VBox;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.List;
import java.util.concurrent.TimeUnit;

/**
 * Main controller for the JavaFX application window.
 * Manages navigation, content switching, and plugin injection.
 */
public class MainController implements LocaleChangeListener {

    private static final Logger logger = LoggerFactory.getLogger(MainController.class);
    private static MainController instance;

    @FXML private VBox navTools;
    @FXML private VBox navPlugins;
    @FXML private VBox navFavorites;
    @FXML private FlowPane toolsGrid;
    @FXML private FlowPane recentGrid;
    @FXML private VBox detailPanel;
    @FXML private Label detailIcon;
    @FXML private Label detailName;
    @FXML private Label detailMeta;
    @FXML private Label detailDesc;
    @FXML private Label statusTools;
    @FXML private Label statusPlugins;
    @FXML private Label statusClock;

    private StackPane contentArea;
    private SwissKitPageScaner.ScannedPages scannedPages;
    private int selectedNavIndex = -1;

    public MainController() {
        instance = this;
    }

    public static MainController getInstance() {
        return instance;
    }

    /**
     * Initialize the controller after FXML injection.
     * Sets up navigation, loads plugins, and starts the clock.
     */
    @FXML
    public void initialize() {
        I18nManager.addListener(this);

        // Scan for pages
        scannedPages = SwissKitPageScaner.scan();

        // Build navigation
        buildNavigation();

        // Update status bar
        updateStatusBar();

        // Select first page
        if (!navTools.getChildren().isEmpty()) {
            selectNavItem(0);
        }

        // Start clock update
        startClock();

        logger.info("MainController initialized with {} pages", scannedPages.totalCount());
    }

    private void buildNavigation() {
        navTools.getChildren().clear();
        navPlugins.getChildren().clear();

        // Built-in tools
        for (Object page : scannedPages.builtinPages()) {
            String name = SwissKitPageScaner.getMenuName(page);
            String tooltip = SwissKitPageScaner.getMenuTooltip(page);
            HBox navItem = createNavItem(name, tooltip, page);
            navTools.getChildren().add(navItem);
        }

        // Plugin tools
        for (Object page : scannedPages.pluginPages()) {
            String name = SwissKitPageScaner.getMenuName(page);
            String tooltip = SwissKitPageScaner.getMenuTooltip(page);
            HBox navItem = createNavItem(name, tooltip, page);
            navItem.getStyleClass().add("plugin-item");
            navPlugins.getChildren().add(navItem);
        }

        // Update badges
        updateNavBadge(navTools, scannedPages.builtinPages().size());
        updateNavBadge(navPlugins, scannedPages.pluginPages().size());
    }

    private HBox createNavItem(String name, String tooltip, Object page) {
        HBox item = new HBox();
        item.getStyleClass().add("nav-item");
        item.setAlignment(javafx.geometry.Pos.CENTER_LEFT);
        item.setSpacing(10);

        Label icon = new Label("●");
        icon.getStyleClass().add("nav-icon");

        Label text = new Label(name);
        text.getStyleClass().add("nav-text");

        item.getChildren().addAll(icon, text);

        if (tooltip != null && !tooltip.isEmpty()) {
            item.setTooltip(new Tooltip(tooltip));
        }

        // Click handler
        item.setOnMouseClicked(e -> {
            int index = navTools.getChildren().indexOf(item);
            if (index >= 0) {
                selectNavItem(index);
            } else {
                index = navPlugins.getChildren().indexOf(item);
                if (index >= 0) {
                    selectPluginItem(index);
                }
            }
        });

        return item;
    }

    private void updateNavBadge(VBox container, int count) {
        // Badge is in parent, find it
        // Implementation depends on FXML structure
    }

    /**
     * Select a built-in tool by index.
     */
    public void selectNavItem(int index) {
        selectedNavIndex = index;
        List<Object> pages = scannedPages.builtinPages();
        if (index >= 0 && index < pages.size()) {
            Object page = pages.get(index);
            showPage(page);
            updateNavSelection(navTools, index);
        }
    }

    /**
     * Select a plugin tool by index.
     */
    public void selectPluginItem(int index) {
        List<Object> pages = scannedPages.pluginPages();
        if (index >= 0 && index < pages.size()) {
            Object page = pages.get(index);
            showPage(page);
            updateNavSelection(navPlugins, index);
        }
    }

    /**
     * Show a page's content in the content area.
     * The page's Node is obtained via reflection from getNode() method.
     */
    private void showPage(Object page) {
        try {
            // Use reflection to get Node from page
            Node node;
            try {
                java.lang.reflect.Method method = page.getClass().getMethod("getNode");
                node = (Node) method.invoke(page);
            } catch (NoSuchMethodException e) {
                // Fallback: try getContent()
                try {
                    java.lang.reflect.Method method = page.getClass().getMethod("getContent");
                    node = (Node) method.invoke(page);
                } catch (NoSuchMethodException ex) {
                    logger.warn("Page {} has no getNode() or getContent() method", page.getClass().getName());
                    return;
                }
            }

            if (contentArea != null) {
                contentArea.getChildren().setAll(node);
            }
        } catch (Exception e) {
            logger.error("Failed to show page: {}", page.getClass().getName(), e);
        }
    }

    private void updateNavSelection(VBox navBox, int selectedIndex) {
        for (int i = 0; i < navBox.getChildren().size(); i++) {
            Node item = navBox.getChildren().get(i);
            if (i == selectedIndex) {
                item.getStyleClass().add("selected");
            } else {
                item.getStyleClass().remove("selected");
            }
        }
    }

    private void updateStatusBar() {
        if (statusTools != null) {
            statusTools.setText(scannedPages.builtinPages().size() + " 个工具");
        }
        if (statusPlugins != null) {
            statusPlugins.setText(scannedPages.pluginPages().size() + " 个插件已加载");
        }
    }

    private void startClock() {
        Thread clockThread = new Thread(() -> {
            while (true) {
                try {
                    String time = LocalDateTime.now().format(
                            DateTimeFormatter.ofPattern("HH:mm:ss"));
                    javafx.application.Platform.runLater(() -> {
                        if (statusClock != null) {
                            statusClock.setText(time);
                        }
                    });
                    TimeUnit.SECONDS.sleep(1);
                } catch (InterruptedException e) {
                    break;
                }
            }
        }, "ClockThread");
        clockThread.setDaemon(true);
        clockThread.start();
    }

    @FXML
    public void openSettings() {
        // Navigate to settings page
        logger.info("Opening settings");
    }

    @FXML
    public void closeDetail() {
        detailPanel.setVisible(false);
        detailPanel.setManaged(false);
    }

    @FXML
    public void launchTool() {
        logger.info("Launching tool: {}", detailName.getText());
    }

    /**
     * Inject a plugin's Node into the content area.
     * Called by PluginRegistry when a plugin page is selected.
     */
    public void injectPluginContent(Node pluginNode) {
        if (contentArea != null) {
            contentArea.getChildren().setAll(pluginNode);
        }
    }

    /**
     * Get the content area for plugin injection.
     */
    public StackPane getContentArea() {
        return contentArea;
    }

    public void setContentArea(StackPane contentArea) {
        this.contentArea = contentArea;
    }

    @Override
    public void onLocaleChanged(Language newLanguage) {
        // Rebuild navigation with new language
        buildNavigation();
    }
}

