/**
 * Main controller for the application window.
 * Coordinates sidebar navigation, tool grid display, and plugin injection.
 *
 * @author summer
 * @version 1.00
 * @date 2026/5/13
 */
public class MainController {

    private static final Logger logger = LoggerFactory.getLogger(MainController.class);

    // Navigation sections
    @FXML private VBox navTools;
    @FXML private VBox navPlugins;
    @FXML private VBox navFavorites;

    // Content area
    @FXML private FlowPane toolsGrid;
    @FXML private FlowPane recentGrid;
    @FXML private VBox detailPanel;

    // Detail panel fields
    @FXML private Label detailIcon;
    @FXML private Label detailName;
    @FXML private Label detailMeta;
    @FXML private Label detailDesc;
    @FXML private Label dpVersion;
    @FXML private Label dpType;
    @FXML private Label dpCat;
    @FXML private Label dpLast;

    // Status bar
    @FXML private Label statusTools;
    @FXML private Label statusPlugins;
    @FXML private Label statusClock;

    // Search
    @FXML private javafx.scene.control.TextField searchField;

    private final ScheduledExecutorService clockExecutor = Executors.newSingleThreadScheduledExecutor();

    // ── Lifecycle ─────────────────────────────────────────────────────────────

    /**
     * Called after FXML fields are injected.
     * Initializes UI components, loads pages, and starts background services.
     */
    public void initialize() {
        logger.info("MainController initializing...");

        // Load and register all pages
        SwissKitPageScaner.ScannedPages scannedPages = SwissKitPageScaner.scan();

        // Populate sidebar navigation
        populateSidebar(scannedPages);

        // Build tool grid
        buildToolsGrid(scannedPages.toFlatList());

        // Update status bar
        statusTools.setText(scannedPages.builtinPages().size() + " 个工具");
        statusPlugins.setText(scannedPages.pluginPages().size() + " 个插件已加载");

        // Start clock
        startClock();

        // Setup search filtering
        searchField.textProperty().addListener((obs, oldVal, newVal) -> filterTools(newVal));

        logger.info("MainController initialized with {} pages", scannedPages.totalCount());
    }

    /**
     * Cleanup resources when controller is no longer needed.
     */
    public void shutdown() {
        clockExecutor.shutdown();
    }

    // ── Sidebar ───────────────────────────────────────────────────────────────

    /**
     * Populates sidebar navigation with built-in tools and plugin tools.
     */
    private void populateSidebar(SwissKitPageScaner.ScannedPages pages) {
        // Built-in tools
        for (Object page : pages.builtinPages()) {
            navTools.getChildren().add(createNavItem(page));
        }

        // Plugin tools
        for (Object page : pages.pluginPages()) {
            navPlugins.getChildren().add(createNavItem(page));
        }
    }

    /**
     * Creates a navigation item for a KitPage.
     * Uses reflection to call getNode() on the page to get JavaFX Node.
     */
    private Node createNavItem(Object page) {
        try {
            // Try to get JavaFX Node from page (via reflection or interface)
            Node node = getNodeFromPage(page);

            // Apply nav-item style class
            node.getStyleClass().add("nav-item");

            // Store page reference for click handling
            node.setUserData(page);

            // Click handler to show tool detail
            node.setOnMouseClicked(e -> showToolDetail(page));

            return node;
        } catch (Exception e) {
            logger.warn("Failed to create nav item for {}: {}", page.getClass().getName(), e.getMessage());
            Label fallback = new Label(getPageName(page));
            fallback.getStyleClass().add("nav-item");
            fallback.setUserData(page);
            fallback.setOnMouseClicked(e -> showToolDetail(page));
            return fallback;
        }
    }

    /**
     * Gets JavaFX Node from a KitPage implementation.
     * Pages can implement getNode() method or return a Node via their panel method.
     */
    private Node getNodeFromPage(Object page) throws Exception {
        // Try getNode() method first (for JavaFX pages)
        try {
            var method = page.getClass().getMethod("getNode");
            return (Node) method.invoke(page);
        } catch (NoSuchMethodException ignored) {}

        // Fallback: call getPanel() and wrap in JavaFX if needed
        // This maintains compatibility with existing KitPage implementations
        try {
            var method = page.getClass().getMethod("getPanel");
            Object panel = method.invoke(page);
            if (panel instanceof Node) {
                return (Node) panel;
            }
        } catch (NoSuchMethodException ignored) {}

        // Last resort: create placeholder
        Label placeholder = new Label(getPageName(page));
        placeholder.setPrefHeight(40);
        return placeholder;
    }

    // ── Tool Grid ─────────────────────────────────────────────────────────────

    /**
     * Builds the tools grid with card layout for each page.
     */
    private void buildToolsGrid(List<Object> pages) {
        toolsGrid.getChildren().clear();

        for (Object page : pages) {
            toolsGrid.getChildren().add(createToolCard(page));
        }
    }

    /**
     * Creates a tool card Node for the grid.
     */
    private Node createToolCard(Object page) {
        VBox card = new VBox();
        card.getStyleClass().add("tool-card");
        card.setPrefWidth(148);
        card.setPrefHeight(120);
        card.setUserData(page);

        // Icon
        Label icon = new Label(getPageIcon(page));
        icon.getStyleClass().add("tool-icon-wrap");
        icon.setAlignment(javafx.geometry.Pos.CENTER);

        // Name
        Label name = new Label(getPageName(page));
        name.getStyleClass().add("tool-name");

        // Description
        String desc = getPageDescription(page);
        Label description = new Label(desc != null ? desc : "");
        description.getStyleClass().add("tool-desc");
        description.setMaxWidth(130);
        description.setEllipsisString("...");

        // Tag (built-in or plugin)
        String tagText = isPluginPage(page) ? "插件" : "内置";
        Label tag = new Label(tagText);
        tag.getStyleClass().add("tool-tag");
        if (isPluginPage(page)) {
            tag.getStyleClass().add("plugin");
        }

        card.getChildren().addAll(icon, name, description, tag);

        // Click to show detail
        card.setOnMouseClicked(e -> showToolDetail(page));

        return card;
    }

    // ── Detail Panel ─────────────────────────────────────────────────────────

    /**
     * Shows the detail panel for a tool.
     */
    private void showToolDetail(Object page) {
        detailIcon.setText(getPageIcon(page));
        detailName.setText(getPageName(page));
        detailMeta.setText("v" + getPageVersion(page) + " · " + (isPluginPage(page) ? "插件" : "内置"));
        detailDesc.setText(getPageDescription(page) != null ? getPageDescription(page) : "");

        dpVersion.setText(getPageVersion(page));
        dpType.setText(isPluginPage(page) ? "插件" : "内置");
        dpCat.setText(getPageCategory(page));
        dpLast.setText("—"); // TODO: track last used

        // Show detail panel
        detailPanel.setManaged(true);
        detailPanel.setVisible(true);
    }

    @FXML
    private void closeDetail() {
        detailPanel.setManaged(false);
        detailPanel.setVisible(false);
    }

    @FXML
    private void launchTool() {
        // Get selected tool from detail panel and launch its view
        Node card = (Node) toolsGrid.getChildren().stream()
                .filter(n -> n instanceof VBox && ((VBox) n).getUserData() != null)
                .findFirst()
                .orElse(null);

        if (card != null && card.getUserData() != null) {
            launchPage((Object) card.getUserData());
        }
    }

    /**
     * Launches a page's view in the main content area.
     * Plugin pages can inject their own Node via getNode().
     */
    private void launchPage(Object page) {
        try {
            Node node = getNodeFromPage(page);

            // For plugin pages, the injected Node IS the tool view
            // For built-in pages, use existing mechanism
            showView(node);

            logger.info("Launched page: {}", page.getClass().getSimpleName());
        } catch (Exception e) {
            logger.error("Failed to launch page {}: {}", page.getClass().getName(), e.getMessage());
        }
    }

    /**
     * Shows a Node in the main content area, replacing current content.
     * This is where plugins inject their UI via the PluginAPI.
     */
    private void showView(Node view) {
        // Clear main content and show the view
        // This would replace the grid with the tool's actual UI
        logger.info("Showing view: {}", view.getClass().getSimpleName());
        // TODO: Implement proper view switching mechanism
    }

    // ── Page Metadata Helpers ─────────────────────────────────────────────────

    private String getPageName(Object page) {
        SwissKitPage annotation = page.getClass().getAnnotation(SwissKitPage.class);
        return annotation != null && !annotation.menuName().isEmpty()
                ? annotation.menuName()
                : page.getClass().getSimpleName().replace("KitPage", "");
    }

    private String getPageIcon(Object page) {
        SwissKitPage annotation = page.getClass().getAnnotation(SwissKitPage.class);
        if (annotation != null && !annotation.iconPath().isEmpty()) {
            return annotation.iconPath().isEmpty() ? "🔧" : annotation.iconPath();
        }
        return "🔧"; // default
    }

    private String getPageVersion(Object page) {
        SwissKitPage annotation = page.getClass().getAnnotation(SwissKitPage.class);
        return annotation != null && !annotation.pluginVersion().isEmpty()
                ? annotation.pluginVersion()
                : "1.0.0";
    }

    private String getPageDescription(Object page) {
        SwissKitPage annotation = page.getClass().getAnnotation(SwissKitPage.class);
        return annotation != null ? annotation.menuTooltip() : null;
    }

    private String getPageCategory(Object page) {
        String className = page.getClass().getName();
        if (className.contains(".excel.")) return "开发";
        if (className.contains(".email.")) return "开发";
        if (className.contains(".setting.")) return "设置";
        if (className.contains(".welcome.")) return "首页";
        return "工具";
    }

    private boolean isPluginPage(Object page) {
        return SwissKitPageScaner.getPluginName(page) != null;
    }

    // ── Search ─────────────────────────────────────────────────────────────────

    private void filterTools(String query) {
        logger.debug("Filtering tools with query: {}", query);
        // TODO: Implement search filtering
    }

    // ── Settings ───────────────────────────────────────────────────────────────

    @FXML
    private void openSettings() {
        logger.info("Opening settings...");
        // TODO: Navigate to settings page
    }

    // ── Clock ──────────────────────────────────────────────────────────────────

    private void startClock() {
        DateTimeFormatter formatter = DateTimeFormatter.ofPattern("HH:mm:ss");
        clockExecutor.scheduleAtFixedRate(() -> {
            Platform.runLater(() -> {
                statusClock.setText(LocalDateTime.now().format(formatter));
            });
        }, 0, 1, TimeUnit.SECONDS);
    }

    // ── Plugin System ───────────────────────────────────────────────────────────

    /**
     * Called when a plugin is installed/enabled/disabled.
     * Refreshes the sidebar and tool grid.
     */
    public void onPluginChanged(List<Object> pluginPages, PluginMetadata metadata) {
        logger.info("Plugin changed: {}, pages: {}", metadata.getPluginName(), pluginPages.size());
    }
}
