package fan.summer.annoattion;

import java.lang.annotation.ElementType;
import java.lang.annotation.Retention;
import java.lang.annotation.RetentionPolicy;
import java.lang.annotation.Target;

/**
 * Annotation to mark a class as a KitPage implementation.
 * Used for automatic page registration and menu configuration.
 *
 * <h2>Usage Example:</h2>
 * <pre>
 * {@code @SwissKitPage(menuName = "Excel", menuTooltip = "Excel file processing", order = 1)}
 * public class ExcelKitPage extends JPanel {
 *     public ExcelKitPage() {
 *         // initialize your UI
 *     }
 * }
 * </pre>
 *
 * @author phoebej
 * @since 1.0.0
 */
@Retention(RetentionPolicy.RUNTIME)
@Target(ElementType.TYPE)
public @interface SwissKitPage {

    /**
     * Unique identifier for the plugin.
     * Used for plugin lifecycle management and dependency resolution.
     *
     * @return plugin name
     */
    String pluginName() default "";

    /**
     * Version string of the plugin in semver format (e.g., "1.0.0").
     * Used for compatibility checks and update detection.
     *
     * @return plugin version
     */
    String pluginVersion() default "";

    /**
     * Menu display name shown in the sidebar navigation.
     * If empty, the simple class name will be used as fallback.
     *
     * @return menu display name
     */
    String menuName();

    /**
     * Resource bundle key for menu display name (for i18n support).
     * If non-empty, the menu name will be looked up from the i18n bundle
     * instead of using menuName directly.
     * Example: "menu.excel" will resolve to localized text.
     *
     * @return menu name i18n key, or empty for no i18n lookup
     */
    String menuNameKey() default "";

    /**
     * Menu tooltip text shown on hover.
     *
     * @return tooltip text
     */
    String menuTooltip() default "";

    /**
     * Whether this page is visible in the menu.
     * Set to false to hide from menu but keep the page accessible programmatically.
     *
     * @return true if visible, false otherwise
     */
    boolean visible() default true;

    /**
     * Menu item order for sorting.
     * Lower values appear first in the menu.
     *
     * @return order value
     */
    int order() default 0;

    /**
     * Menu icon path (optional).
     * Can be a classpath resource path or file path.
     *
     * @return icon path, or empty string for no icon
     */
    String iconPath() default "";

    /**
     * Method name to retrieve the panel from the page (Swing).
     * The annotated class must have a public method with this name
     * that returns a {@link javax.swing.JPanel}.
     *
     * @return panel retrieval method name
     */
    String panelMethod() default "getPanel";

    /**
     * Method name to retrieve the content Node from the page (JavaFX).
     * The annotated class must have a public method with this name
     * that returns a {@link javafx.scene.Node}.
     *
     * @return node retrieval method name
     */
    String nodeMethod() default "getContent";
}

package fan.summer.api;

import javafx.scene.Node;

/**
 * Plugin API interface that plugins use to communicate with the host application.
 * Each plugin receives a PluginContext instance when it is loaded.
 *
 * <p>Plugins should implement KitPage to be discovered, and can optionally
 * implement this interface to receive lifecycle callbacks.</p>
 *
 * <p>Example plugin implementation:</p>
 * <pre>{@code
 * @SwissKitPage(menuName = "My Tool", order = 10)
 * public class MyToolPage implements KitPage, PluginAPI {
 *     private Node content;
 *     private PluginContext context;
 *
 *     @Override
 *     public Node getContent() {
 *         return content;
 *     }
 *
 *     @Override
 *     public void onLoad(PluginContext context) {
 *         this.context = context;
 *         // Initialize plugin resources
 *     }
 *
 *     @Override
 *     public void onUnload() {
 *         // Cleanup resources
 *     }
 *
 *     @Override
 *     public void onSelected() {
 *         // Plugin was selected in UI
 *     }
 * }
 * }</pre>
 */
public interface PluginAPI {

    /**
     * Called when the plugin is loaded by the host application.
     *
     * @param context provides access to host services
     */
    default void onLoad(PluginContext context) {}

    /**
     * Called when the plugin is unloaded or the application shuts down.
     * Release any resources acquired during onLoad().
     */
    default void onUnload() {}

    /**
     * Called when the plugin is selected/activated in the UI.
     * Use this to refresh data or start background tasks.
     */
    default void onSelected() {}

    /**
     * Called when the plugin is deselected.
     * Use this to pause background tasks or save state.
     */
    default void onDeselected() {}

    /**
     * Returns the main content Node for this plugin.
     * This will be injected into the application's content area.
     *
     * @return the Node to display
     */
    Node getContent();

    /**
     * Returns metadata about this plugin.
     *
     * @return plugin metadata
     */
    default PluginAPIMetadata getMetadata() {
        return new PluginAPIMetadata(getClass().getSimpleName(), "1.0.0");
    }

    /**
     * Context interface providing access to host application services.
     */
    interface PluginContext {
        /**
         * Get the application stage controller.
         */
        Object getMainController();

        /**
         * Get the plugin registry for registering content.
         */
        PluginRegistry getRegistry();

        /**
         * Get a configuration value.
         *
         * @param key configuration key
         * @return configuration value or null
         */
        String getConfig(String key);

        /**
         * Show a notification to the user.
         *
         * @param message notification message
         * @param type notification type (info, warning, error)
         */
        void showNotification(String message, NotificationType type);

        /**
         * Get the current locale.
         */
        String getLocale();
    }

    /**
     * Notification type for showNotification.
     */
    enum NotificationType {
        INFO,
        WARNING,
        ERROR
    }

    /**
     * Metadata about this plugin API implementation.
     */
    record PluginAPIMetadata(String name, String version) {}
}

