101	    private static void sortPages(List<Object> pages) {
102	        pages.sort(Comparator
103	                .comparingInt((Object p) -> {
104	                    Integer saved = savedMenuOrders.get(p.getClass().getName());
105	                    return saved != null ? saved : Integer.MAX_VALUE;
106	                })
107	                .thenComparingInt(p -> getAnnotationOrder(p))
108	                .thenComparing(p -> p.getClass().getName())
109	        );
110	    }
111	
112	    private static int getAnnotationOrder(Object page) {
113	        SwissKitPage annotation = page.getClass().getAnnotation(SwissKitPage.class);
114	        return annotation != null ? annotation.order() : Integer.MAX_VALUE;
115	    }
116	
117	    private static void loadSavedMenuOrders() {
118	        savedMenuOrders.clear();
