1	package fan.summer.api.content;
2	
3	import com.toolbox.api.ToolPlugin;
4	import javafx.animation.FadeTransition;
5	import javafx.animation.ParallelTransition;
6	import javafx.animation.PauseTransition;
7	import javafx.animation.TranslateTransition;
8	import javafx.collections.ListChangeListener;
9	import javafx.collections.ObservableList;
10	import javafx.geometry.Insets;
11	import javafx.geometry.Pos;
12	import javafx.scene.Node;
13	import javafx.scene.control.Label;
14	import javafx.scene.control.ScrollPane;
15	import javafx.scene.control.TextField;
16	import javafx.scene.layout.*;
17	import javafx.util.Duration;
18	
19	import java.util.List;
20	import java.util.function.Consumer;
21	
22	/**
23	 * 主内容区。
24	 * 包含：搜索栏 / 工具网格 / 详情面板 / 页面切换动画。
25	 * 通过 setPlugins(ObservableList) 绑定插件数据，自动响应增删。
26	 */
27	public class ContentArea extends BorderPane {
28	
29	    // ── 子组件 ────────────────────────────────────────────
30	    private final TextField   searchField  = new TextField();
31	    private final FlowPane    toolGrid     = new FlowPane();
32	    private final DetailPanel detailPanel  = new DetailPanel();
33	    private final StackPane   pageStack    = new StackPane();
34	    private final ScrollPane  scrollPane;
35	
36	    // ── 状态 ──────────────────────────────────────────────
37	    private ObservableList<ToolPlugin> plugins;
38	    private String   currentCategory = "all";
39	    private String   currentQuery    = "";
40	    private Consumer<ToolPlugin> onLaunch;
41	
42	    public ContentArea() {
43	        scrollPane = buildScrollPane();
44	        buildLayout();
45	        detailPanel.setOnLaunch(p -> { if (onLaunch != null) onLaunch.accept(p); });
46	    }
47	
48	    // ── 公共 API ──────────────────────────────────────────
49	
50	    public void setOnLaunch(Consumer<ToolPlugin> handler) { this.onLaunch = handler; }
51	
52	    /** 绑定插件列表，增删自动刷新 */
53	    public void setPlugins(ObservableList<ToolPlugin> list) {
54	        this.plugins = list;
55	        list.addListener((ListChangeListener<ToolPlugin>) c -> refresh());
56	        refresh();
57	    }
58	
59	    /** 切换显示分类 */
60	    public void showCategory(String categoryId) {
61	        currentCategory = categoryId;
62	        searchField.clear();
63	        currentQuery = "";
64	        crossFadeTo(scrollPane);
65	        refresh();
66	        animateGridIn();
67	    }
68	
69	    /** 切换到自定义页面（如设置、插件市场） */
70	    public void showPage(Node page, String title) {
71	        crossFadeTo(page);
72	        detailPanel.hide();
73	    }
74	
75	    /** 回到工具网格主页 */
76	    public void showToolGrid() {
77	        crossFadeTo(scrollPane);
78	    }
79	
80	    // ── 布局构建 ──────────────────────────────────────────
81	
82	    private void buildLayout() {
83	        // 搜索栏
84	        HBox searchBar = buildSearchBar();
85	        VBox top = new VBox(searchBar);
86	        top.setPadding(new Insets(12, 16, 0, 16));
87	        setTop(top);
88	
89	        // 中间：StackPane（内容可切换） + 详情面板
90	        pageStack.getChildren().add(scrollPane);
91	        pageStack.setAlignment(Pos.TOP_LEFT);
92	
93	        HBox center = new HBox(pageStack, detailPanel);
94	        HBox.setHgrow(pageStack, Priority.ALWAYS);
95	        setCenter(center);
96	    }
97	
98	    private HBox buildSearchBar() {
99	        Label searchIcon = new Label("🔍");
100	        searchIcon.setStyle("-fx-font-size: 13px; -fx-text-fill: rgba(255,255,255,0.28);");
101	
102	        searchField.getStyleClass().add("search-field");
103	        searchField.setPromptText("搜索工具...");
104	        searchField.setMaxWidth(Double.MAX_VALUE);
105	        HBox.setHgrow(searchField, Priority.ALWAYS);
106	        searchField.textProperty().addListener((obs, oldVal, newVal) -> {
107	            currentQuery = newVal.trim().toLowerCase();
108	            refresh();
109	        });
110	
111	        Label kbdHint = new Label("⌘K");
112	        kbdHint.setStyle(
113	            "-fx-font-size: 10px; -fx-text-fill: rgba(255,255,255,0.28);" +
114	            "-fx-background-color: rgba(255,255,255,0.06);" +
115	            "-fx-border-color: rgba(255,255,255,0.10); -fx-border-width: 1;" +
116	            "-fx-border-radius: 4; -fx-background-radius: 4;" +
117	            "-fx-padding: 1 5 1 5; -fx-font-family: 'SF Mono','Consolas',monospace;"
118	        );
119	
120	        HBox bar = new HBox(10, searchIcon, searchField, kbdHint);
121	        bar.getStyleClass().add("search-bar");
122	        bar.setAlignment(Pos.CENTER_LEFT);
123	        bar.setPrefHeight(38);
124	        return bar;
125	    }
126	
127	    private ScrollPane buildScrollPane() {
128	        // 工具网格
129	        toolGrid.setHgap(10);
130	        toolGrid.setVgap(10);
131	        toolGrid.setPadding(new Insets(16));
132	        toolGrid.setPrefWrapLength(600);
133	
134	        VBox wrapper = new VBox(
135	            sectionHeader("常用工具", ""),
136	            toolGrid
137	        );
138	        wrapper.setPadding(new Insets(8, 16, 16, 16));
139	        wrapper.setSpacing(0);
140	
141	        ScrollPane sp = new ScrollPane(wrapper);
142	        sp.getStyleClass().add("content-scroll");
143	        sp.setFitToWidth(true);
144	        sp.setHbarPolicy(ScrollPane.ScrollBarPolicy.NEVER);
145	        sp.setVbarPolicy(ScrollPane.ScrollBarPolicy.AS_NEEDED);
146	        sp.setStyle("-fx-background-color: transparent; -fx-background: transparent;");
147	        return sp;
148	    }
149	
150	    // ── 网格刷新 ──────────────────────────────────────────
151	
152	    private void refresh() {
153	        if (plugins == null) return;
154	
155	        List<ToolPlugin> filtered = plugins.stream()
156	            .filter(this::matchesCategory)
157	            .filter(this::matchesQuery)
158	            .toList();
159	
160	        toolGrid.getChildren().clear();
161	
162	        for (int i = 0; i < filtered.size(); i++) {
163	            ToolPlugin p = filtered.get(i);
164	            ToolCard card = new ToolCard(p, this::onCardSelect);
165	            card.setPrefWidth(152);
166	            card.setPrefHeight(130);
167	
168	            // 错开入场延迟
169	            int delay = i * 35;
170	            card.setOpacity(0);
171	            PauseTransition pause = new PauseTransition(Duration.millis(delay));
172	            pause.setOnFinished(e -> {
173	                FadeTransition ft = new FadeTransition(Duration.millis(240), card);
174	                ft.setFromValue(0); ft.setToValue(1);
175	                TranslateTransition tt = new TranslateTransition(Duration.millis(240), card);
176	                tt.setFromY(10); tt.setToY(0);
177	                new ParallelTransition(ft, tt).play();
178	            });
179	            pause.play();
180	
181	            toolGrid.getChildren().add(card);
182	        }
183	
184	        // 空状态提示
185	        if (filtered.isEmpty()) {
186	            Label empty = new Label("没有找到匹配的工具");
187	            empty.setStyle("-fx-text-fill: rgba(255,255,255,0.28); -fx-font-size: 13px;");
188	            empty.setPadding(new Insets(40, 0, 0, 0));
189	            toolGrid.getChildren().add(empty);
190	        }
191	    }
192	
193	    // ── 过滤逻辑 ──────────────────────────────────────────
194	
195	    private boolean matchesCategory(ToolPlugin p) {
196	        return switch (currentCategory) {
197	            case "all"     -> true;
198	            case "plugins" -> !"builtin".equals(p.getType());
199	            case "fav"     -> false; // TODO: 接入收藏持久化
200	            default        -> p.getCategory().equalsIgnoreCase(currentCategory);
201	        };
202	    }
203	
204	    private boolean matchesQuery(ToolPlugin p) {
205	        if (currentQuery.isEmpty()) return true;
206	        return p.getName().toLowerCase().contains(currentQuery)
207	            || p.getDescription().toLowerCase().contains(currentQuery);
208	    }
209	
210	    // ── 卡片选中 ──────────────────────────────────────────
211	
212	    private void onCardSelect(ToolPlugin plugin) {
213	        detailPanel.show(plugin);
214	    }
215	
216	    // ── 页面切换动画（交叉淡入淡出） ──────────────────────
217	
218	    private void crossFadeTo(Node next) {
219	        Node current = pageStack.getChildren().isEmpty()
220	            ? null : pageStack.getChildren().get(0);
221	
222	        next.setOpacity(0);
223	        if (!pageStack.getChildren().contains(next))
224	            pageStack.getChildren().add(next);
225	        next.toFront();
226	
227	        FadeTransition fadeIn = new FadeTransition(Duration.millis(220), next);
