package fan.summer.api.content;

import com.toolbox.api.ToolPlugin;
import javafx.animation.*;
import javafx.geometry.Insets;
import javafx.scene.control.Label;
import javafx.scene.layout.Priority;
import javafx.scene.layout.StackPane;
import javafx.scene.layout.VBox;
import javafx.util.Duration;

import java.util.function.Consumer;

/**
 * 工具网格中的单个卡片。
 * 点击后回调 onSelect，由父组件决定打开详情面板或启动工具。
 */
public class ToolCard extends VBox {

    private final ToolPlugin plugin;

    public ToolCard(ToolPlugin plugin, Consumer<ToolPlugin> onSelect) {
        this.plugin = plugin;
        getStyleClass().add("tool-card");
        setSpacing(3);
        setPadding(new Insets(16, 14, 14, 14));

        // ── 图标 ────────────────────────────────────────
        Label iconLabel = new Label(plugin.getIconText());
        iconLabel.setStyle("-fx-font-size: 18px;");

        StackPane iconWrap = new StackPane(iconLabel);
        iconWrap.getStyleClass().addAll("tool-icon-wrap", plugin.getIconStyle());
        iconWrap.setPrefSize(40, 40);
        iconWrap.setMinSize(40, 40);

        // ── 文字 ────────────────────────────────────────
        Label nameLabel = new Label(plugin.getName());
        nameLabel.getStyleClass().add("tool-name");
        nameLabel.setMaxWidth(Double.MAX_VALUE);

        Label descLabel = new Label(plugin.getDescription());
        descLabel.getStyleClass().add("tool-desc");
        descLabel.setWrapText(true);
        descLabel.setMaxWidth(Double.MAX_VALUE);
        VBox.setVgrow(descLabel, Priority.ALWAYS);

        // ── 标签 ────────────────────────────────────────
        boolean isPlugin = !"builtin".equals(plugin.getType());
        Label tag = new Label(isPlugin ? "插件" : "内置");
        tag.getStyleClass().addAll("tool-tag", isPlugin ? "tool-tag-plugin" : "");

        getChildren().addAll(iconWrap, nameLabel, descLabel, tag);

        // ── 悬停动画 ─────────────────────────────────────
        ScaleTransition hoverIn  = new ScaleTransition(Duration.millis(150), this);
        ScaleTransition hoverOut = new ScaleTransition(Duration.millis(150), this);
        hoverIn.setToX(1.03); hoverIn.setToY(1.03);
        hoverOut.setToX(1.0); hoverOut.setToY(1.0);

        setOnMouseEntered(e -> { hoverOut.stop(); hoverIn.play(); });
        setOnMouseExited( e -> { hoverIn.stop(); hoverOut.play(); });

        // ── 点击动画 + 回调 ───────────────────────────────
        setOnMouseClicked(e -> {
            ScaleTransition click = new ScaleTransition(Duration.millis(100), this);
            click.setToX(0.97); click.setToY(0.97);
            click.setAutoReverse(true); click.setCycleCount(2);
            click.setOnFinished(ev -> onSelect.accept(plugin));
            click.play();
        });

        // ── 入场动画 ─────────────────────────────────────
        setOpacity(0);
        setScaleX(0.94); setScaleY(0.94);
        setTranslateY(8);

        FadeTransition ft = new FadeTransition(Duration.millis(280), this);
        ft.setToValue(1);
        TranslateTransition tt = new TranslateTransition(Duration.millis(280), this);
        tt.setToY(0);
        ScaleTransition st = new ScaleTransition(Duration.millis(280), this);
        st.setToX(1); st.setToY(1);

        ParallelTransition entry = new ParallelTransition(ft, tt, st);
        entry.setInterpolator(new Interpolator() {
            @Override protected double curve(double t) {
                // 简易弹性曲线
                return 1 - Math.pow(1 - t, 3) * Math.cos(t * Math.PI * 2);
            }
        });
        // 延迟由外部调用者设置，见 ToolGrid
        entry.play();

        setCursor(javafx.scene.Cursor.HAND);
    }

    public ToolPlugin getPlugin() { return plugin; }
}

package fan.summer.app;

import com.toolbox.plugin.PluginLoader;
import com.toolbox.plugin.PluginRegistry;
import com.toolbox.ui.MainWindow;
import fan.summer.Registrar.BuiltinToolRegistrar;
import javafx.application.Application;
import javafx.scene.Scene;
import javafx.scene.paint.Color;
import javafx.stage.Stage;
import javafx.stage.StageStyle;

import java.nio.file.Path;
import java.nio.file.Paths;

/**
 * Application entry point.
 * Startup sequence:
 *   1. Determine plugins/ directory
 *   2. Create PluginLoader + PluginRegistry
 *   3. Register built-in tools
 *   4. Build MainWindow and display
 *   5. Start PluginLoader (scan JARs + start file watcher)
 */
public class SwissKitJApp extends Application {

    private MainWindow mainWindow;

    @Override
    public void start(Stage stage) throws Exception {

        // ── Plugin directory (prefer JAR sibling, fallback to working directory during dev) ──
        Path pluginsDir = resolvePluginsDir();

        // ── Plugin system ──────────────────────────────────────
        PluginLoader   loader   = new PluginLoader(pluginsDir);
        PluginRegistry registry = new PluginRegistry(loader);

        // ── Register built-in tools ──────────────────────────────
        BuiltinToolRegistrar.register(loader, registry);

        // ── Main window ────────────────────────────────────────
        mainWindow = new MainWindow(stage, loader, registry);

        // Transparent scene (for rounded window to display correctly)
        Scene scene = new Scene(mainWindow, 960, 620);
        scene.setFill(Color.TRANSPARENT);
        scene.getStylesheets().add(
            getClass().getResource("/com/toolbox/css/glass.css").toExternalForm()
        );

        // Undecorated window (custom titlebar via TitleBar)
        stage.initStyle(StageStyle.TRANSPARENT);
        stage.setTitle("ToolBox");
        stage.setScene(scene);
        stage.setMinWidth(800);
        stage.setMinHeight(520);
        stage.show();

        // ── Start plugin loading (after UI is displayed) ────────
        loader.start();
    }

    @Override
    public void stop() {
        if (mainWindow != null) mainWindow.shutdown();
    }

    // ── Helper: locate plugins directory ───────────────────────────

    private Path resolvePluginsDir() {
        // Try JAR sibling directory
        try {
            Path jar = Paths.get(
                SwissKitJApp.class.getProtectionDomain()
                    .getCodeSource().getLocation().toURI()
            );
            Path candidate = jar.getParent().resolve("plugins");
            if (candidate.toFile().isDirectory()) return candidate;
        } catch (Exception ignored) {}

        // Dev mode: plugins/ under working directory
        return Paths.get("plugins");
    }

    public static void main(String[] args) {
        launch(args);
    }
}

package fan.summer;

/**
 * Fat JAR / classpath launch entry point.
 *
 * Must be separate from ToolboxApp (extends Application).
 * JavaFX module system requires: when using a class that extends Application
 * as the main class, javafx.graphics needs to be on the module-path,
 * not classpath. Using this non-Application intermediate class for launch
 * allows compatibility with classpath mode (lib/ directory).
 */
public class Launcher {
    public static void main(String[] args) {
        fan.summer.app.SwissKitJApp.main(args);
    }
}

