1:package fan.summer.api;
3:import com.toolbox.plugin.PluginLoader;
4:import com.toolbox.plugin.PluginRegistry;
5:import com.toolbox.ui.content.ContentArea;
6:import com.toolbox.ui.sidebar.Sidebar;
7:import com.toolbox.ui.titlebar.TitleBar;
8:import javafx.animation.*;
9:import javafx.geometry.Insets;
10:import javafx.geometry.Pos;
11:import javafx.scene.control.Label;
12:import javafx.scene.layout.*;
13:import javafx.scene.paint.Color;
14:import javafx.scene.shape.Circle;
15:import javafx.scene.shape.Rectangle;
16:import javafx.stage.Stage;
17:import javafx.util.Duration;
19:import java.time.LocalTime;
20:import java.time.format.DateTimeFormatter;
23: * Root node of the main window.
24: * Assembles TitleBar / Sidebar / ContentArea / StatusBar,
25: * and holds the lifecycle for PluginLoader and PluginRegistry.
27:public class MainWindow extends StackPane {
29:    private final Stage        stage;
30:    private final PluginLoader loader;
31:    private final PluginRegistry registry;
33:    private final TitleBar    titleBar;
34:    private final Sidebar     sidebar;
35:    private final ContentArea contentArea;
37:    // Status bar labels
38:    private final Label statusToolCount    = statusText("0 tools");
39:    private final Label statusPluginCount  = statusText("0 plugins");
40:    private final Label clockLabel         = statusText("");
42:    private Timeline clockTimeline;
44:    public MainWindow(Stage stage, PluginLoader loader, PluginRegistry registry) {
45:        this.stage    = stage;
46:        this.loader   = loader;
47:        this.registry = registry;
49:        titleBar    = new TitleBar(stage, this::openSettings);
50:        sidebar     = new Sidebar();
51:        contentArea = new ContentArea();
53:        buildScene();
54:        wireEvents();
55:        startClock();
56:        playEntryAnimation();
59:    // ── Build scene graph ────────────────────────────────
61:    private void buildScene() {
62:        // Background orb layer (bottom layer)
63:        Pane orbLayer = buildOrbLayer();
65:        // Main window glass panel
66:        BorderPane windowPane = new BorderPane();
67:        windowPane.getStyleClass().add("app-root");
68:        windowPane.setStyle(
69:            "-fx-background-color: rgba(13,14,17,0.72);" +
70:            "-fx-background-radius: 20;" +
71:            "-fx-border-radius: 20;" +
72:            "-fx-border-color: rgba(255,255,255,0.10);" +
73:            "-fx-border-width: 1;" +
74:            "-fx-effect: dropshadow(gaussian, rgba(0,0,0,0.6), 60, 0, 0, 20);"
75:        );
77:        // Title bar
78:        windowPane.setTop(titleBar);
80:        // Body: sidebar + content area
81:        HBox body = new HBox(sidebar, contentArea);
82:        HBox.setHgrow(contentArea, Priority.ALWAYS);
83:        windowPane.setCenter(body);
85:        // Status bar
86:        windowPane.setBottom(buildStatusBar());
88:        // Top highlight border (glass thickness simulation)
89:        Rectangle topHighlight = new Rectangle();
90:        topHighlight.setMouseTransparent(true);
91:        topHighlight.setStyle(
92:            "-fx-fill: transparent;" +
93:            "-fx-stroke: rgba(255,255,255,0.12);" +
94:            "-fx-stroke-width: 1;" +
95:            "-fx-arc-width: 40; -fx-arc-height: 40;"
96:        );
97:        topHighlight.widthProperty().bind(widthProperty());
98:        topHighlight.heightProperty().bind(heightProperty());
100:        getChildren().addAll(orbLayer, windowPane, topHighlight);
101:        setAlignment(windowPane, Pos.CENTER);
102:        setAlignment(topHighlight, Pos.CENTER);
105:    // ── Background orbs ───────────────────────────────────
107:    private Pane buildOrbLayer() {
108:        Pane layer = new Pane();
109:        layer.setMouseTransparent(true);
110:        layer.setStyle("-fx-background-color: #0d0e11;");
112:        // Three colored Gaussian blur orbs
113:        layer.getChildren().addAll(
114:            orb(480, "#3b5bdb", -80, -120, 0),
115:            orb(360, "#7048e8",  -60, 200,  -6000),
116:            orb(300, "#1c7ed6",  300, 400, -12000)
117:        );
118:        return layer;
121:    private StackPane orb(double size, String color, double x, double y, double animDelay) {
122:        Circle c = new Circle(size / 2,
123:            Color.web(color, 0.28));
124:        c.setEffect(new javafx.scene.effect.GaussianBlur(60));
126:        StackPane wrap = new StackPane(c);
127:        wrap.setTranslateX(x);
128:        wrap.setTranslateY(y);
129:        wrap.setMouseTransparent(true);
131:        // Floating animation
132:        TranslateTransition drift = new TranslateTransition(Duration.millis(18000), wrap);
133:        drift.setByX(30); drift.setByY(20);
134:        drift.setAutoReverse(true);
135:        drift.setCycleCount(Animation.INDEFINITE);
136:        drift.setDelay(Duration.millis(Math.abs(animDelay)));
137:        drift.setInterpolator(Interpolator.EASE_BOTH);
138:        drift.play();
140:        ScaleTransition breathe = new ScaleTransition(Duration.millis(12000), wrap);
141:        breathe.setFromX(1.0); breathe.setFromY(1.0);
142:        breathe.setToX(1.08);  breathe.setToY(1.08);
143:        breathe.setAutoReverse(true);
144:        breathe.setCycleCount(Animation.INDEFINITE);
145:        breathe.setInterpolator(Interpolator.EASE_BOTH);
146:        breathe.play();
148:        return wrap;
151:    // ── Status bar ───────────────────────────────────────
153:    private HBox buildStatusBar() {
154:        // Activity indicator dot
155:        Circle dot = new Circle(3, Color.web("#4cd97b"));
156:        dot.setEffect(new javafx.scene.effect.Glow(0.8));
157:        FadeTransition pulse = new FadeTransition(Duration.millis(2500), dot);
158:        pulse.setFromValue(1.0); pulse.setToValue(0.4);
159:        pulse.setAutoReverse(true); pulse.setCycleCount(Animation.INDEFINITE);
160:        pulse.play();
162:        Label sep = statusText("·");
163:        sep.setStyle("-fx-text-fill: rgba(255,255,255,0.15); -fx-font-size: 11px;");
165:        Region spacer = new Region();
166:        HBox.setHgrow(spacer, Priority.ALWAYS);
168:        HBox bar = new HBox(10);
169:        bar.getStyleClass().add("statusbar");
170:        bar.setAlignment(Pos.CENTER_LEFT);
171:        bar.setPadding(new Insets(0, 16, 0, 16));
172:        bar.getChildren().addAll(dot, statusToolCount, sep, statusPluginCount, spacer, clockLabel);
173:        return bar;
176:    private Label statusText(String text) {
177:        Label l = new Label(text);
178:        l.getStyleClass().add("status-text");
179:        return l;
182:    // ── Event wiring ─────────────────────────────────────
184:    private void wireEvents() {
185:        // Bind plugin list to content area
186:        contentArea.setPlugins(registry.getPlugins());
188:        // Sidebar category switch → content area filter
189:        sidebar.setOnCategorySelect(categoryId -> {
190:            contentArea.showCategory(categoryId);
191:        });
193:        // Settings (standalone, not part of nav state machine)
194:        sidebar.setOnSettingsSelect(this::openSettings);
196:        // Plugin list change → update status bar
197:        registry.getPlugins().addListener(
198:            (javafx.collections.ListChangeListener<com.toolbox.api.ToolPlugin>) c -> {
199:                int total   = registry.getPlugins().size();
200:                int plugins = (int) registry.getPlugins().stream()
201:                    .filter(p -> !"builtin".equals(p.getType())).count();
202:                statusToolCount.setText(total + " tools");
203:                statusPluginCount.setText(plugins + " plugins");
204:                sidebar.updateBadge("plugins", plugins);
206:        );
208:        // Tool launch callback
209:        contentArea.setOnLaunch(plugin -> {
210:            registry.activate(plugin);
211:            contentArea.showPage(plugin.createView(), plugin.getName());
212:        });
215:    // ── Settings page ────────────────────────────────────
217:    private void openSettings() {
218:        Label placeholder = new Label("⚙️  Settings Panel\n(Coming soon)");
219:        placeholder.setStyle(
220:            "-fx-text-fill: rgba(255,255,255,0.40); -fx-font-size: 16px;" +
221:            "-fx-alignment: center; -fx-text-alignment: center;"
222:        );
223:        StackPane page = new StackPane(placeholder);
224:        page.setStyle("-fx-background-color: transparent;");
225:        contentArea.showPage(page, "Settings");
228:    // ── Entry animation ──────────────────────────────────
230:    private void playEntryAnimation() {
231:        // Get windowPane (second child node)
232:        javafx.scene.Node windowPane = getChildren().get(1);
233:        windowPane.setOpacity(0);
234:        windowPane.setScaleX(0.94);
235:        windowPane.setScaleY(0.94);
236:        windowPane.setTranslateY(16);
238:        FadeTransition ft = new FadeTransition(Duration.millis(500), windowPane);
239:        ft.setToValue(1);
241:        ScaleTransition st = new ScaleTransition(Duration.millis(500), windowPane);
242:        st.setToX(1); st.setToY(1);
243:        st.setInterpolator(Interpolator.SPLINE(0.34, 0.9, 0.64, 1.0));
245:        TranslateTransition tt = new TranslateTransition(Duration.millis(500), windowPane);
246:        tt.setToY(0);
247:        tt.setInterpolator(Interpolator.SPLINE(0.34, 0.9, 0.64, 1.0));
249:        new ParallelTransition(ft, st, tt).play();
252:    // ── Clock ────────────────────────────────────────────
254:    private void startClock() {
255:        DateTimeFormatter fmt = DateTimeFormatter.ofPattern("HH:mm:ss");
256:        clockTimeline = new Timeline(new KeyFrame(Duration.seconds(1), e ->
257:            clockLabel.setText(LocalTime.now().format(fmt))
258:        ));
259:        clockTimeline.setCycleCount(Animation.INDEFINITE);
260:        clockTimeline.play();
261:        clockLabel.setText(LocalTime.now().format(fmt)); // Initial display
264:    /** Called on application exit to clean up resources */
266:        if (clockTimeline != null) clockTimeline.stop();
267:        loader.stop();

