package fan.summer.buildintool.excelsplitter;

import java.nio.file.Path;
import java.util.List;

/**
 * 向导各步骤收集的配置，在步骤间传递。
 */
public class SplitConfig {

    public enum SplitMode {
        BY_SHEET("按工作表拆分"),
        BY_COLUMN("按列值拆分"),
        BY_ROW_COUNT("按行数拆分");

        public final String label;
        SplitMode(String label) { this.label = label; }
    }

    // 步骤一：源文件
    public Path   sourceFile;
    public List<String> sheetNames;   // 源文件所有 Sheet 名

    // 步骤二：拆分方式
    public SplitMode mode = SplitMode.BY_SHEET;

    // BY_COLUMN 专用
    public String splitColumn;        // 列标题名
    public int    splitColumnIndex;   // 列索引（0-based）

    // BY_ROW_COUNT 专用
    public int rowsPerFile = 1000;

    // BY_SHEET 专用
    public List<String> selectedSheets; // 要拆分的 Sheet，null 表示全部

    // 步骤三：输出设置
    public Path   outputDir;
    public String filePrefix = "";    // 输出文件名前缀
    public boolean keepHeader = true; // 按列/行拆分时是否保留表头

    @Override
    public String toString() {
        return "SplitConfig{mode=" + mode + ", source=" + sourceFile + "}";
    }
}

