267	    }
268	
269	    // ── 颜色转换 ──────────────────────────────────────────
270	
271	    private static ToolPlugin colorConverter() {
272	        return new SimpleToolPlugin(
273	            "builtin.color", "颜色转换",
274	            "HEX / RGB / HSL 互转，实时预览",
275	            "image", "1.0.0", "◉", "ic-pink"
276	        ) {
277	            @Override public Node createView() {
278	                TextField hexField = styledField("#5b8cf7");
279	                TextField rgbField = styledField("91, 140, 247");
