19	public class ExcelSplitterPlugin implements ToolPlugin {
20	
21	    private Node      view;
22	    private SplitConfig config;
23	
24	    // ── 元信息 ────────────────────────────────────────────
25	
26	    @Override public String getId()          { return "com.toolbox.excel-splitter"; }
27	    @Override public String getName()        { return "Excel 拆分"; }
