34	
35	    @Override
36	    public void onActivate() {
37	        // 每次进入重置向导，方便重新拆分
38	        view = null;
39	    }
40	
41	    @Override
42	    public Node createView() {
43	        if (view != null) return view;
44	        config = new SplitConfig();
