65	        addNavItem("dev",     "⌨️", "开发工具",  3, false);
66	        addNavItem("net",     "📡", "网络工具",  2, false);
67	
68	        getChildren().add(divider());
69	
70	        // ── 插件分区 ────────────────────────────────────
71	        getChildren().add(sectionLabel("插件"));
72	        addNavItem("plugins", "🧩", "已安装插件", 3, true);
73	        addNavItem("store",   "🏪", "插件市场",   0, false);
74	
75	        getChildren().add(divider());
76	
77	        // ── 收藏分区 ────────────────────────────────────
78	        getChildren().add(sectionLabel("收藏"));
79	        addNavItem("fav", "⭐", "我的收藏", 5, false);
80	
81	        // ── 底部弹簧 + 设置 ──────────────────────────────
82	        Region spacer = new Region();
83	        VBox.setVgrow(spacer, Priority.ALWAYS);
84	        getChildren().add(spacer);
85	        getChildren().add(divider());
