    private String   currentCategory = "all";
    private String   currentQuery    = "";
    private Consumer<ToolPlugin> onLaunch;

    public ContentArea() {
        scrollPane = buildScrollPane();
        buildLayout();
        detailPanel.setOnLaunch(p -> { if (onLaunch != null) onLaunch.accept(p); });
    }

    // ── 公共 API ──────────────────────────────────────────

    public void setOnLaunch(Consumer<ToolPlugin> handler) { this.onLaunch = handler; }

    /** 绑定插件列表，增删自动刷新 */
    public void setPlugins(ObservableList<ToolPlugin> list) {
